#include<bits/stdc++.h>
using namespace std;
int n,m,dp[301][301][301];
long long a,b,c,d,e,f;
set<pair<long long,long long>> mp;
const int mod=998244353;
void solve(int i,int j,int k,int l)
{
    if(mp.find(make_pair(i*a+j*c+k*e,i*b+j*d+k*f))==mp.end())
    {
        dp[i][j][k]+=l;
        dp[i][j][k]%=mod;
    }
}
int main()
{
    cin>>n>>m>>a>>b>>c>>d>>e>>f;
    for(int i=1;i<=m;i++)
    {
        long long x,y;
        scanf("%lld%lld",&x,&y);
        mp.insert(make_pair(x,y));
    }
    dp[0][0][0]=1;
    for(int i=0;i<n;i++)
    {
        for(int j=0;i+j<n;j++)
        {
            for(int k=0;i+j+k<n;k++)
            {
                if(dp[i][j][k])
                {
                    solve(i+1,j,k,dp[i][j][k]);
                    solve(i,j+1,k,dp[i][j][k]);
                    solve(i,j,k+1,dp[i][j][k]);
                }
            }
        }
    }
    int ans=0;
    for(int i=0;i<=n;i++)
    {
        for(int j=0;i+j<=n;j++)
        {
            int k=n-i-j;
            ans+=dp[i][j][k];
            ans%=mod;
        }
    }
    printf("%d",ans);
    return 0;
}
